import React, { useEffect, useState } from 'react';
import axios from 'axios';
import Navbar from '../components/Navbar';
import LoadCard from '../components/LoadCard';

export default function Dashboard() {
  const [loads, setLoads] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:5000/api/loads').then(res => setLoads(res.data));
  }, []);

  return (
    <div className="min-h-screen bg-truckYellow">
      <Navbar />
      <div className="p-8">
        <h1 className="text-4xl font-black text-truckRed mb-8 uppercase italic underline decoration-white">Driver Dashboard</h1>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {loads.map(load => (
            <LoadCard key={load._id} load={load} />
          ))}
        </div>
      </div>
    </div>
  );
}
